object ProductionLogger {
    private lateinit var appContext: Context
    private lateinit var fileLoggingTree: FileLoggingTree
    private val sessionId = UUID.randomUUID().toString().substring(0, 8)

    fun initialize(context: Context) {
        appContext = context.applicationContext
        fileLoggingTree = FileLoggingTree(appContext)

        // Plant Timber trees
        Timber.plant(VerboseDebugTree())
        Timber.plant(fileLoggingTree)
        Timber.plant(CrashReportingTree())

        Timber.i("=== Production Logger Initialized === Session: $sessionId")
        Timber.i("App Version: ${getAppVersion()}")
        Timber.i("Device: ${Build.MANUFACTURER} ${Build.MODEL}")
        Timber.i("Android Version: ${Build.VERSION.RELEASE} (SDK ${Build.VERSION.SDK_INT})")
    }

    fun shutdown() {
        fileLoggingTree.flush()
        Timber.i("=== Production Logger Shutdown === Session: $sessionId")
    }

    private fun getAppVersion(): String {
        return try {
            val pInfo = appContext.packageManager.getPackageInfo(appContext.packageName, 0)
            "${pInfo.versionName} (${pInfo.longVersionCode})"
        } catch (e: Exception) {
            "unknown"
        }
    }

    fun getSessionId(): String = sessionId

    fun getLogFile(context: Context): File {
        return File(context.filesDir, "logs/production_log.txt")
    }
}

// ============================================================
// Verbose Debug Tree - Console output with full details
// ============================================================
class VerboseDebugTree : Timber.DebugTree() {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val timestamp = dateFormat.format(Date())
        val threadName = Thread.currentThread().name
        val priorityChar = when (priority) {
            Log.VERBOSE -> "V"
            Log.DEBUG -> "D"
            Log.INFO -> "I"
            Log.WARN -> "W"
            Log.ERROR -> "E"
            Log.ASSERT -> "A"
            else -> "?"
        }

        val formattedMessage = "[$timestamp][$priorityChar][$threadName] $message"
        super.log(priority, tag, formattedMessage, t)
    }

    override fun createStackElementTag(element: StackTraceElement): String {
        return "(${element.fileName}:${element.lineNumber})#${element.methodName}"
    }
}

// ============================================================
// File Logging Tree - Persistent log storage
// ============================================================
class FileLoggingTree(private val context: Context) : Timber.Tree() {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val logBuffer = ConcurrentLinkedQueue<String>()
    private val executor = Executors.newSingleThreadScheduledExecutor()
    private val maxFileSize = 10 * 1024 * 1024L // 10MB
    private val maxLogFiles = 5

    init {
        // Flush buffer to file every 5 seconds
        executor.scheduleAtFixedRate({ flush() }, 5, 5, TimeUnit.SECONDS)
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val timestamp = dateFormat.format(Date())
        val priorityChar = when (priority) {
            Log.VERBOSE -> "V"
            Log.DEBUG -> "D"
            Log.INFO -> "I"
            Log.WARN -> "W"
            Log.ERROR -> "E"
            Log.ASSERT -> "A"
            else -> "?"
        }

        val logLine = buildString {
            append("$timestamp | $priorityChar | ${tag ?: "---"} | $message")
            if (t != null) {
                append("\n")
                append(getFullStackTrace(t))
            }
        }

        logBuffer.add(logLine)

        // Immediate flush for errors
        if (priority >= Log.ERROR) {
            flush()
        }
    }

    fun flush() {
        if (logBuffer.isEmpty()) return

        try {
            val logDir = File(context.filesDir, "logs")
            if (!logDir.exists()) logDir.mkdirs()

            val logFile = File(logDir, "production_log.txt")

            // Rotate if needed
            if (logFile.exists() && logFile.length() > maxFileSize) {
                rotateLogFiles(logDir)
            }

            FileWriter(logFile, true).use { writer ->
                while (logBuffer.isNotEmpty()) {
                    val entry = logBuffer.poll() ?: break
                    writer.write(entry)
                    writer.write("\n")
                }
                writer.flush()
            }
        } catch (e: Exception) {
            Log.e("FileLoggingTree", "Failed to write logs to file", e)
        }
    }

    private fun rotateLogFiles(logDir: File) {
        // Delete oldest if at max
        val oldestFile = File(logDir, "production_log_$maxLogFiles.txt")
        if (oldestFile.exists()) oldestFile.delete()

        // Rotate existing files
        for (i in maxLogFiles - 1 downTo 1) {
            val file = File(logDir, "production_log_$i.txt")
            if (file.exists()) {
                file.renameTo(File(logDir, "production_log_${i + 1}.txt"))
            }
        }

        // Rotate current file
        val currentFile = File(logDir, "production_log.txt")
        currentFile.renameTo(File(logDir, "production_log_1.txt"))
    }

    private fun getFullStackTrace(t: Throwable): String {
        val sw = StringWriter()
        val pw = PrintWriter(sw)
        t.printStackTrace(pw)
        return sw.toString()
    }
}

// ============================================================
// Crash Reporting Tree - Captures errors for crash reporting
// ============================================================
class CrashReportingTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (priority < Log.WARN) return

        // In production, this would send to Crashlytics, Sentry, etc.
        if (t != null && priority >= Log.ERROR) {
            // CrashReporter.logException(t)
            Timber.tag("CRASH_REPORT").v("Exception captured for reporting: ${t.javaClass.simpleName}: ${t.message}")
        }
    }
}

