object AuthLogger {
    private const val TAG = "AUTH"

    fun logLoginAttempt(username: String, method: String, ipAddress: String? = null) {
        Timber.tag(TAG).i(
            """
            |╔══════════════════════════════════════
            |║ LOGIN ATTEMPT
            |║ Username: ${maskSensitive(username)}
            |║ Method: $method
            |║ IP Address: ${ipAddress ?: "unknown"}
            |║ Timestamp: ${System.currentTimeMillis()}
            |║ Device ID: ${Build.FINGERPRINT}
            |╚══════════════════════════════════════
            """.trimMargin()
        )
    }

    fun logLoginSuccess(
        username: String,
        userId: String,
        method: String,
        tokenExpiry: Long? = null,
        roles: List<String>? = null
    ) {
        Timber.tag(TAG).i(
            """
            |╔══════════════════════════════════════
            |║ ✅ LOGIN SUCCESS
            |║ Username: ${maskSensitive(username)}
            |║ User ID: $userId
            |║ Method: $method
            |║ Token Expiry: ${tokenExpiry?.let { Date(it) } ?: "N/A"}
            |║ Roles: ${roles?.joinToString(", ") ?: "N/A"}
            |║ Session Started: ${Date()}
            |╚══════════════════════════════════════
            """.trimMargin()
        )
    }

    fun logLoginFailure(
        username: String,
        method: String,
        reason: String,
        errorCode: Int? = null,
        exception: Throwable? = null,
        attemptNumber: Int? = null
    ) {
        Timber.tag(TAG).w(
            exception,
            """
            |╔══════════════════════════════════════
            |║ ❌ LOGIN FAILURE
            |║ Username: ${maskSensitive(username)}
            |║ Method: $method
            |║ Reason: $reason
            |║ Error Code: ${errorCode ?: "N/A"}
            |║ Attempt #: ${attemptNumber ?: "N/A"}
            |║ Exception: ${exception?.javaClass?.simpleName ?: "None"}
            |║ Exception Message: ${exception?.message ?: "None"}
            |║ Timestamp: ${Date()}
            |╚══════════════════════════════════════
            """.trimMargin()
        )
    }

    fun logLogout(userId: String, reason: String = "user_initiated") {
        Timber.tag(TAG).i(
            """
            |╔══════════════════════════════════════
            |║ LOGOUT
            |║ User ID: $userId
            |║ Reason: $reason
            |║ Timestamp: ${Date()}
            |╚══════════════════════════════════════
            """.trimMargin()
        )
    }

    fun logTokenRefresh(userId: String, success: Boolean, newExpiry: Long? = null, error: String? = null) {
        if (success) {
            Timber.tag(TAG).i(
                "TOKEN REFRESH SUCCESS | User: $userId | New Expiry: ${newExpiry?.let { Date(it) }}"
            )
        } else {
            Timber.tag(TAG).w(
                "TOKEN REFRESH FAILED | User: $userId | Error: $error"
            )
        }
    }

    fun logPasswordResetRequest(email: String) {
        Timber.tag(TAG).i("PASSWORD RESET REQUESTED | Email: ${maskEmail(email)} | Timestamp: ${Date()}")
    }

    fun logAccountLocked(username: String, reason: String, lockDuration: Long?) {
        Timber.tag(TAG).w(
            """
            |╔══════════════════════════════════════
            |║ ⚠️ ACCOUNT LOCKED
            |║ Username: ${maskSensitive(username)}
            |║ Reason: $reason
            |║ Lock Duration: ${lockDuration?.let { "${it / 1000}s" } ?: "indefinite"}
            |║ Timestamp: ${Date()}
            |╚══════════════════════════════════════
            """.trimMargin()
        )
    }

    fun logBiometricAuth(userId: String, success: Boolean, biometricType: String, error: String? = null) {
        Timber.tag(TAG).i(
            "BIOMETRIC AUTH | User: $userId | Type: $biometricType | Success: $success | Error: ${error ?: "None"}"
        )
    }

    private fun maskSensitive(value: String): String {
        if (value.length <= 3) return "***"
        return value.take(2) + "*".repeat(value.length - 3) + value.takeLast(1)
    }

    private fun maskEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***@***"
        return maskSensitive(parts[0]) + "@" + parts[1]
    }
}

